#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int num, rev = 0, digit;
        scanf("%d", &num);
        int sign = 1;
        if (num < 0) { sign = -1; num = -num; }
        while (num != 0) {
            digit = num % 10;
            rev = rev * 10 + digit;
            num /= 10;
        }
        printf("%d\n", sign * rev);
    }
    return 0;
}

