const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = parseInt(input[idx++]);
let results = [];
for (let i = 0; i < T; i++) {
  let num = parseInt(input[idx++]);
  let sign = 1;
  if (num < 0) { sign = -1; num = -num; }
  let rev = 0;
  while (num !== 0) {
    rev = rev * 10 + (num % 10);
    num = Math.floor(num / 10);
  }
  results.push(String(sign * rev));
}
